import{c as o,Q as s,j as t,m as a}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"How do I focus on a single customer?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/focus-on-customer.md","filePath":"guide/recipes/admin/focus-on-customer.md","lastUpdated":1778912818000}'),r={name:"guide/recipes/admin/focus-on-customer.md"};function n(i,e,c,u,l,d){return s(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="how-do-i-focus-on-a-single-customer" tabindex="-1">How do I focus on a single customer? <a class="header-anchor" href="#how-do-i-focus-on-a-single-customer" aria-label="Permalink to &quot;How do I focus on a single customer?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong>, <strong>Infra Ops</strong>, <strong>Finance Admin</strong>, or any role with broad cross-customer access</p></div><p>Focus mode narrows the Console&#39;s aggregate views to a single customer for the duration of your session. It&#39;s a viewing convenience — your <em>permissions</em> are unchanged.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open the customer&#39;s detail page (<strong>Customers → &lt;name&gt;</strong>).</li><li>Click <strong>Focus on this customer</strong> in the header.</li><li>The header changes to show a focus banner with the customer name.</li></ol><p>To exit, click <strong>Exit Focus</strong> in the banner.</p><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><ul><li>Dashboard, Tenant Insights, Migrations, Audit Log, and other aggregate views filter to this customer only.</li><li>Internal-user-only pages (Internal Users, System Workers, etc.) are unaffected — they&#39;re not customer-scoped.</li><li>You can still navigate to a different customer&#39;s page; focus only changes the <em>aggregate</em> views.</li></ul><div class="tip custom-block"><p class="custom-block-title">Why this is useful</p><p>When you&#39;re working a support ticket for one customer, focus mode keeps unrelated activity out of your dashboards so you can spot the customer&#39;s signal without cross-customer noise.</p></div>',9)])])}const g=o(r,[["render",n]]);export{h as __pageData,g as default};
